class Solution:
    def mapWordWeights(self, words, weights):
        out_chars = []
        for w in words:
            total = 0
            for ch in w:
                total = total + weights[ord(ch) - ord('a')]
            r = total % 26
            out_chars.append(chr(ord('a') + (25 - r)))
        return ''.join(out_chars)

