class Solution:
    def mapWordWeights(self, words: 'list[str]', weights: 'list[int]') -> str:
        result = []
        for word in words:
            weight = sum(weights[ord(ch) - ord('a')] for ch in word)
            mapped = chr(ord('z') - (weight % 26))
            result.append(mapped)
        return ''.join(result)

