var mapWordWeights = function(words, weights) {
    let result = '';
    for (const word of words) {
        let weight = 0;
        for (const ch of word) {
            weight += weights[ch.charCodeAt(0) - 97];
        }
        const mapped = String.fromCharCode(122 - (weight % 26));
        result += mapped;
    }
    return result;
};
